   101→// Data fetching hook
   102→const useApi = (url, options = {}) => {
   103→  const [data, setData] = useState(null);
   104→  const [loading, setLoading] = useState(true);
   105→  const [error, setError] = useState(null);
   106→
   107→  useEffect(() => {
