   111→        const result = await response.json();
   112→        setData(result);
   113→      } catch (err) {
   114→        setError(err);
   115→      } finally {
   116→        setLoading(false);
   117→      }
   118→    };
   119→
   120→    fetchData();
   121→  }, [url]);
   122→
   123→  return { data, loading, error };
   124→};
   125→
   126→// Form handling hook
   127→const useForm = (initialValues, validationSchema) => {
   128→  const [values, setValues] = useState(initialValues);
   129→  const [errors, setErrors] = useState({});
   130→  const [touched, setTouched] = useState({});
   131→
   132→  const handleChange = (name, value) => {
   133→    setValues(prev => ({ ...prev, [name]: value }));
   134→    if (touched[name]) {
   135→      validateField(name, value);
   136→    }
   137→  };
   138→
   139→  const handleBlur = (name) => {
   140→    setTouched(prev => ({ ...prev, [name]: true }));
   141→    validateField(name, values[name]);
   142→  };
   143→
   144→  const validateField = async (name, value) => {
