   364→
   365→### **Keyboard Navigation & Focus Management**
   366→```javascript
   367→// Focus trap for modals
   368→const Modal = ({ isOpen, onClose, children }) => {
   369→  const modalRef = useRef();
   370→
   371→  useEffect(() => {
   372→    if (isOpen) {
   373→      modalRef.current.focus();
   374→    }
   375→  }, [isOpen]);
   376→
   377→  const handleKeyDown = (e) => {
